<?php
namespace Tests\Feature\Hr;use Illuminate\Support\Facades\Artisan;use Illuminate\Support\Facades\Schema;use Tests\TestCase;
class HrPhase6BAnalyticsRollbackTest extends TestCase{use RefreshHrDatabase;public function test_snapshot_schema_exists():void{$this->assertTrue(Schema::hasColumns('hr_analytics_snapshots',['metrics','sources','source_hash','generated_at']));}public function test_rollback_preserves_compensation():void{Artisan::call('migrate:rollback',['--step' => 4]);Artisan::call('migrate:rollback', ['--step' => 1]);$this->assertFalse(Schema::hasTable('hr_analytics_snapshots'));$this->assertTrue(Schema::hasTable('hr_salary_records'));$this->assertTrue(Schema::hasTable('hr_onboarding_checklists'));}}
